CREATE TRIGGER LG_EMUHACC_INS_524 ON LG_524_EMUHACC
FOR INSERT
AS
DECLARE @new_Code       VARCHAR(110),
        @sBuffer        VARCHAR(110),
        @upperRef       INT,
        @new_accountRef INT,
        @new_level      INT
SELECT @new_accountRef = I.LOGICALREF,
       @new_Code= I.CODE,
       @new_level = I.LEVEL_
FROM INSERTED I
SET @upperRef = @new_accountRef
WHILE (@upperRef <> 0)
 BEGIN
    INSERT INTO LG_524_EMUHACCSUBACCASGN VALUES(@upperRef,@new_accountRef)
    EXEC LG_GETEMUHACCUPPERCODE_524 @new_Code, @new_level, @sBuffer OUTPUT, @upperRef OUTPUT
    SET @new_level = @new_level -1
 END
